template_code:
Type Maillon = Enregistrement
Debut
    idx  : Entier;
    suiv : ^Maillon;
Fin;

Type PileIdx = Enregistrement
Debut
    sommet : ^Maillon;
Fin;

Procedure Init(Var P : PileIdx)
Debut
    P.sommet := NIL;
Fin;

Procedure Empiler(Var P : PileIdx, i : Entier)
Var n : ^Maillon;
Debut
    n := allouer(taille(Maillon));
    n->idx := i;
    n->suiv := P.sommet;
    P.sommet := n;
Fin;

Procedure Depiler(Var P : PileIdx, Var i : Entier)
Var t : ^Maillon;
Debut
    t := P.sommet;
    i := t->idx;
    P.sommet := t->suiv;
    liberer(t);
Fin;

Fonction EstVide(P : PileIdx) : Booleen
Debut
    Retourner(P.sommet = NIL);
Fin;

Fonction Sommet(P : PileIdx) : Entier
Debut
    Retourner(P.sommet->idx);
Fin;

Algorithme NextGreater;
Var
    N, i, j : Entier;
    T[100000], R[100000] : Entier;
    P : PileIdx;
Debut
    Lire(N);
    Pour i := 1 a N Faire
        Lire(T[i]);
        R[i] := -1;
    FinPour

    Init(P);

    Pour i := 1 a N Faire
        // TODO: tant que pile non vide et T[i] > T[Sommet(P)], remplir R[]
        // TODO: Empiler(P, i)
    FinPour

    Pour i := 1 a N Faire
        Ecrire(R[i]);
        Si i < N Alors Ecrire(" " ); FinSi
    FinPour
Fin.
